{
    "title": "Tlog message",
    "$schema": "http://json-schema.org/draft-04/schema#",
    "type": "object",
    "properties": {
        "ver": {
            "description": "Message format version",
            "type": "string",
            "pattern": "^[0-9]+(\\.[0-9]+)?$"
        },
        "host": {
            "description": "Name of the host recording was made on",
            "type": "string"
        },
        "rec": {
            "description": "ID of the recording on the host",
            "type": "string"
        },
        "user": {
            "description": "Recorded user name",
            "type": "string"
        },
        "term": {
            "description": "Terminal type name",
            "type": "string"
        },
        "session": {
            "description": "Audit session ID",
            "type": "integer",
            "minimum": 1
        },
        "id": {
            "description": "ID of the message within the recording",
            "type": "integer",
            "minimum": 1
        },
        "pos": {
            "description": "Message position in the recording, milliseconds",
            "type": "integer",
            "minimum": 0
        },
        "timing": {
            "description": "Distribution of this message's events in time",
            "type": "string"
        },
        "in_txt": {
            "description": "Input text with invalid characters scrubbed",
            "type": "string"
        },
        "in_bin": {
            "description": "Scrubbed invalid input characters as bytes",
            "type": "array",
            "items": {
                "type": "integer",
                "minimum": 0,
                "maximum": 255
            }
        },
        "out_txt": {
            "description": "Output text with invalid characters scrubbed",
            "type": "string"
        },
        "out_bin": {
            "description": "Scrubbed invalid output characters as bytes",
            "type": "array",
            "items": {
                "type": "integer",
                "minimum": 0,
                "maximum": 255
            }
        }
    },
    "required": [
        "ver",
        "host",
        "rec",
        "user",
        "term",
        "session",
        "id",
        "pos",
        "timing"
    ]
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "id": "https://opendev.org/openstack/openstacksdk/raw/branch/master/openstack/config/schema.json",
    "type": "object",
    "properties": {
        "auth_type": {
            "name": "Auth Type",
            "description": "Name of authentication plugin to be used",
            "default": "password",
            "type": "string"
        },
        "disable_vendor_agent": {
            "name": "Disable Vendor Agent Properties",
            "description": "Image properties required to disable vendor agent",
            "type": "object",
            "properties": {}
        },
        "floating_ip_source": {
            "name": "Floating IP Source",
            "description": "Which service provides Floating IPs",
            "enum": [
                "neutron",
                "nova",
                "None"
            ],
            "default": "neutron"
        },
        "image_api_use_tasks": {
            "name": "Image Task API",
            "description": "Does the cloud require the Image Task API",
            "default": false,
            "type": "boolean"
        },
        "image_format": {
            "name": "Image Format",
            "description": "Format for uploaded Images",
            "default": "qcow2",
            "type": "string"
        },
        "interface": {
            "name": "API Interface",
            "description": "Which API Interface should connections hit",
            "default": "public",
            "enum": [
                "public",
                "internal",
                "admin"
            ]
        },
        "secgroup_source": {
            "name": "Security Group Source",
            "description": "Which service provides security groups",
            "default": "neutron",
            "enum": [
                "neutron",
                "nova",
                "None"
            ]
        },
        "baremetal_api_version": {
            "name": "Baremetal API Service Type",
            "description": "Baremetal API Service Type",
            "default": "1",
            "type": "string"
        },
        "block_storage_api_version": {
            "name": "Block Storage API Version",
            "description": "Block Storage API Version",
            "default": "2",
            "type": "string"
        },
        "compute_api_version": {
            "name": "Compute API Version",
            "description": "Compute API Version",
            "default": "2",
            "type": "string"
        },
        "database_api_version": {
            "name": "Database API Version",
            "description": "Database API Version",
            "default": "1.0",
            "type": "string"
        },
        "dns_api_version": {
            "name": "DNS API Version",
            "description": "DNS API Version",
            "default": "2",
            "type": "string"
        },
        "identity_api_version": {
            "name": "Identity API Version",
            "description": "Identity API Version",
            "default": "2",
            "type": "string"
        },
        "image_api_version": {
            "name": "Image API Version",
            "description": "Image API Version",
            "default": "1",
            "type": "string"
        },
        "network_api_version": {
            "name": "Network API Version",
            "description": "Network API Version",
            "default": "2",
            "type": "string"
        },
        "object_store_api_version": {
            "name": "Object Storage API Version",
            "description": "Object Storage API Version",
            "default": "1",
            "type": "string"
        },
        "volume_api_version": {
            "name": "Volume API Version",
            "description": "Volume API Version",
            "default": "2",
            "type": "string"
        },
        "vendor_hook": {
            "name": "Hook for vendor customization",
            "description": "A possibility for a vendor to alter connection object",
            "type": "string"
        }
    },
    "required": [
        "auth_type",
        "disable_vendor_agent",
        "floating_ip_source",
        "image_api_use_tasks",
        "image_format",
        "interface",
        "secgroup_source"
    ]
}

{
    "$schema": "http://json-schema.org/draft-04/schema#",
    "title": "JSON Schema for Common Vulnerability Scoring System version 2.0",
    "copyright": "Copyright (c) 2017, Forum of Incident Response and Security Teams, Inc. All rights reserved.",
    "id": "https://www.first.org/cvss/cvss-v2.0.json?20170531",
    "type": "object",
    "definitions": {
        "accessVectorType": {
            "type": "string",
            "enum": [
                "NETWORK",
                "ADJACENT_NETWORK",
                "LOCAL"
            ]
        },
        "accessComplexityType": {
            "type": "string",
            "enum": [
                "HIGH",
                "MEDIUM",
                "LOW"
            ]
        },
        "authenticationType": {
            "type": "string",
            "enum": [
                "MULTIPLE",
                "SINGLE",
                "NONE"
            ]
        },
        "ciaType": {
            "type": "string",
            "enum": [
                "NONE",
                "PARTIAL",
                "COMPLETE"
            ]
        },
        "exploitabilityType": {
            "type": "string",
            "enum": [
                "UNPROVEN",
                "PROOF_OF_CONCEPT",
                "FUNCTIONAL",
                "HIGH",
                "NOT_DEFINED"
            ]
        },
        "remediationLevelType": {
            "type": "string",
            "enum": [
                "OFFICIAL_FIX",
                "TEMPORARY_FIX",
                "WORKAROUND",
                "UNAVAILABLE",
                "NOT_DEFINED"
            ]
        },
        "reportConfidenceType": {
            "type": "string",
            "enum": [
                "UNCONFIRMED",
                "UNCORROBORATED",
                "CONFIRMED",
                "NOT_DEFINED"
            ]
        },
        "collateralDamagePotentialType": {
            "type": "string",
            "enum": [
                "NONE",
                "LOW",
                "LOW_MEDIUM",
                "MEDIUM_HIGH",
                "HIGH",
                "NOT_DEFINED"
            ]
        },
        "targetDistributionType": {
            "type": "string",
            "enum": [
                "NONE",
                "LOW",
                "MEDIUM",
                "HIGH",
                "NOT_DEFINED"
            ]
        },
        "ciaRequirementType": {
            "type": "string",
            "enum": [
                "LOW",
                "MEDIUM",
                "HIGH",
                "NOT_DEFINED"
            ]
        },
        "scoreType": {
            "type": "number",
            "minimum": 0,
            "maximum": 10
        }
    },
    "properties": {
        "version": {
            "description": "CVSS Version",
            "type": "string",
            "enum": [
                "2.0"
            ]
        },
        "vectorString": {
            "type": "string",
            "pattern": "^((AV:[NAL]|AC:[LMH]|Au:[MSN]|[CIA]:[NPC]|E:(U|POC|F|H|ND)|RL:(OF|TF|W|U|ND)|RC:(UC|UR|C|ND)|CDP:(N|L|LM|MH|H|ND)|TD:(N|L|M|H|ND)|[CIA]R:(L|M|H|ND))/)*(AV:[NAL]|AC:[LMH]|Au:[MSN]|[CIA]:[NPC]|E:(U|POC|F|H|ND)|RL:(OF|TF|W|U|ND)|RC:(UC|UR|C|ND)|CDP:(N|L|LM|MH|H|ND)|TD:(N|L|M|H|ND)|[CIA]R:(L|M|H|ND))$"
        },
        "accessVector": {
            "$ref": "#/definitions/accessVectorType"
        },
        "accessComplexity": {
            "$ref": "#/definitions/accessComplexityType"
        },
        "authentication": {
            "$ref": "#/definitions/authenticationType"
        },
        "confidentialityImpact": {
            "$ref": "#/definitions/ciaType"
        },
        "integrityImpact": {
            "$ref": "#/definitions/ciaType"
        },
        "availabilityImpact": {
            "$ref": "#/definitions/ciaType"
        },
        "baseScore": {
            "$ref": "#/definitions/scoreType"
        },
        "exploitability": {
            "$ref": "#/definitions/exploitabilityType"
        },
        "remediationLevel": {
            "$ref": "#/definitions/remediationLevelType"
        },
        "reportConfidence": {
            "$ref": "#/definitions/reportConfidenceType"
        },
        "temporalScore": {
            "$ref": "#/definitions/scoreType"
        },
        "collateralDamagePotential": {
            "$ref": "#/definitions/collateralDamagePotentialType"
        },
        "targetDistribution": {
            "$ref": "#/definitions/targetDistributionType"
        },
        "confidentialityRequirement": {
            "$ref": "#/definitions/ciaRequirementType"
        },
        "integrityRequirement": {
            "$ref": "#/definitions/ciaRequirementType"
        },
        "availabilityRequirement": {
            "$ref": "#/definitions/ciaRequirementType"
        },
        "environmentalScore": {
            "$ref": "#/definitions/scoreType"
        }
    },
    "required": [
        "version",
        "vectorString",
        "baseScore"
    ]
}

