                    "type": "object",
                    "minProperties": 1,
                    "additionalProperties": false,
                    "properties": {
                        "terminal": {
                            "type": "boolean"
                        },
                        "queue": {
                            "type": "boolean"
                        },
                        "recordStatistics": {
                            "type": "boolean"
                        },
                        "includeDestinationId": {
                            "type": "boolean"
                        },
                        "alias": {
                            "type": "boolean"
                        }
                    }
                },
                "matcher": {
                    "minProperties": 1,
                    "additionalProperties": false,
                    "oneOf": [
                        {
                            "type": "object",
                            "properties": {
                                "type": {
                                    "type": "string",
                                    "enum": [
                                        "args",
                                        "none"
                                    ]
                                }
                            },
                            "required": [
                                "type"
                            ]
                        },
                        {
                            "type": "object",
                            "properties": {
                                "type": {
                                    "type": "string",
                                    "const": "exact"
                                },
                                "code": {
                                    "type": "integer"
                                }
                            },
